#include <iostream>
#include <algorithm>
using namespace std;
int main()
{
    int n;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        string s;
        long long quan=1,ans=0,x;
        cin>>x>>s;
        for(int i=s.size()-1;i>=0;i--)
        {
            if(s[i]>='0'&&s[i]<='9')
            {
                ans=ans+(s[i]-'0')*quan;
            }
            else
            {
                ans=ans+(s[i]-'A'+10)*quan;
            }
            quan*=x;
        }
        cout<<ans<<endl;
    }
}
